import { ButtonProps } from ':components/Button';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import { HTMLAttributes, ReactNode } from 'react';
import { TestComponentProps } from 'src/types/test-component';
export type CardTemplateImagePosition = 'top' | 'left' | 'right';
export type CardTemplateVariant = 'default' | 'link';
export interface CardTemplateLabel {
    title: ReactNode;
}
export interface CardTemplateAction extends ButtonProps {
    label: string;
    hidden?: boolean;
    'aria-label'?: string;
}
export interface CardTemplateProps extends HTMLAttributes<HTMLDivElement>, TestComponentProps {
    icon?: Icons;
    /** Картинка карточки: url-строка или ReactNode */
    image?: string | ReactNode;
    imageAlt?: string;
    /** Позиция картинки относительно контента */
    imagePosition?: CardTemplateImagePosition;
    /** Заголовок */
    header?: string;
    /** Подзаголовок/описание */
    headline?: string | ReactNode;
    /** Лейблы */
    labels?: CardTemplateLabel[];
    /** Кнопки */
    actions?: CardTemplateAction[];
    /** Href - если задан то карточка оборачивается в <a> */
    href?: string;
    /** Состояние disabled */
    disabled?: boolean;
    /** Колбэк кликов по действиям */
    onAction?: (action: CardTemplateAction, event?: React.MouseEvent) => void;
}
